CREATE SEQUENCE xeus.${tblId}__gid_seq;

CREATE TABLE xeus.${tblId}
(
    item_nm character varying(100) COLLATE pg_catalog."default",
    item_val numeric(8,0),
    lat numeric(24,8),
    lon numeric(24,8),
    _gid bigint NOT NULL DEFAULT nextval('xeus.${tblId}__gid_seq'::regclass),
    _annox numeric(24,4),
    _annoy numeric(24,4),
    _geometry geometry(Point,5186),
    CONSTRAINT ${tblId}_pk PRIMARY KEY (_gid)
);

CREATE INDEX xeus_${tblId}_gidx ON xeus.${tblId} USING gist (_geometry) TABLESPACE pg_default;

COMMENT ON TABLE  xeus.${tblId} IS '${tblNm}';
COMMENT ON COLUMN xeus.${tblId}."item_nm" IS '항목명';
COMMENT ON COLUMN xeus.${tblId}."item_val" IS '항목값';
COMMENT ON COLUMN xeus.${tblId}."lat" IS '위도';
COMMENT ON COLUMN xeus.${tblId}."lon" IS '경도';
COMMENT ON COLUMN xeus.${tblId}."_gid" IS '도형식별번호';
COMMENT ON COLUMN xeus.${tblId}."_annox" IS '주기X좌표';
COMMENT ON COLUMN xeus.${tblId}."_annoy" IS '주기Y좌표';
COMMENT ON COLUMN xeus.${tblId}."_geometry" IS '도형정보(점)';

CREATE SEQUENCE xeus.${tblId}__gid_seq;

CREATE TABLE xeus.${tblId}
(
    item_nm character varying(100) COLLATE pg_catalog."default",
